import React from "react"

const nav = ({ nav, changeLang }) => (
  <div style={{ position: "fixed", bottom: 0, right: 0, margin: 15 }}>
    {nav ? (
      <div className="level">
        <div className="level-item buttons has-addons">
          <span className="button" onClick={() => changeLang("en")}>
            Eng
          </span>
          <span className="button" onClick={() => changeLang("th")}>
            Thai
          </span>
        </div>
      </div>
    ) : null}
  </div>
)

export default nav
